<?php
namespace App\Domain\Loot;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use InvalidArgumentException;
final class LootConfigurationValidator{private $classification;public function __construct(ItemClassification $classification){$this->classification=$classification;}public function validate(Monster $m,Item $i,int $chance,int $min,int $max,string $status,MonsterLootEntry $existing=null):void{if(!$m->exists||!$i->exists)throw new InvalidArgumentException('References must be persisted.');$this->classification->classify($i);if($chance<0||$chance>10000||$min<1||$max<$min||$min>PHP_INT_MAX||$max>PHP_INT_MAX)throw new InvalidArgumentException('Invalid loot values.');if(!in_array($status,CatalogStatus::values(),true))throw new InvalidArgumentException('Invalid status.');if($existing&&((int)$existing->monster_id!==(int)$m->id||(int)$existing->item_id!==(int)$i->id))throw new InvalidArgumentException('Existing entry mismatch.');$q=MonsterLootEntry::where('monster_id',$m->id)->where('item_id',$i->id);if($existing)$q->where('id','<>',$existing->id);if($q->exists())throw new InvalidArgumentException('Duplicate loot entry.');}}
